    34→	}
    35→
    36→	warning({
    37→		err,
    38→		context,
    39→	}: {
    40→		err: Error | string;
    41→		context?: Record<string, unknown>;
    42→	}): void {
    43→		this.addToBuffer({ level: 'warning', err, context });
    44→	}
    45→
    46→	info({ msg, context }: { msg: string; context?: Record<string, unknown> }): void {
    47→		this.addToBuffer({ level: 'info', err: msg, context });
    48→	}
    49→
    50→	critical({ err, context }: { err: Error; context?: Record<string, unknown> }): void {
    51→		if (context) {
    52→			rollbar.critical(err, context);
    53→		} else {
    54→			rollbar.critical(err);
    55→		}
    56→	}
    57→
    58→	flush(): void {
    59→		for (const [fingerprint, entry] of this.buffer) {
    60→			const context = {
    61→				...entry.context,
    62→				occurrenceCount: entry.count,
    63→				fingerprint,
    64→				firstOccurrence: new Date(entry.firstOccurrence).toISOString(),
    65→			};
    66→
    67→			this.sendToClient({ level: entry.level, err: entry.error, context });
    68→		}
    69→
    70→		this.buffer.clear();
    71→	}
    72→
    73→	wait(): Promise<void> {
    74→		this.flush();
    75→		this.stopIntervals();
    76→
    77→		return new Promise<void>((resolve) => {
    78→			rollbar.wait(() => {
    79→				resolve();
    80→			});
    81→		});
    82→	}
    83→
    84→	getBufferSize(): number {
    85→		return this.buffer.size;
    86→	}
