    88→	private addToBuffer({
    89→		level,
    90→		err,
    91→		context,
    92→	}: {
    93→		level: RollbarLevel;
    94→		err: Error | string;
    95→		context?: Record<string, unknown> | undefined;
    96→	}): void {
    97→		const fingerprint = this.createFingerprint({ level, err });
    98→		const existing = this.buffer.get(fingerprint);
    99→		const now = Date.now();
   100→
   101→		if (existing && now - existing.firstOccurrence < DEDUPE_WINDOW_MS) {
   102→			existing.count++;
   103→			return;
   104→		}
   105→
   106→		if (existing) {
   107→			this.flushSingleEntry({ fingerprint, entry: existing });
   108→		}
   109→
   110→		this.buffer.set(fingerprint, {
   111→			firstOccurrence: now,
   112→			count: 1,
   113→			level,
   114→			error: err,
   115→			context,
   116→		});
   117→	}
   118→
   119→	private flushSingleEntry({
   120→		fingerprint,
   121→		entry,
   122→	}: {
   123→		fingerprint: string;
   124→		entry: BufferedError;
   125→	}): void {
   126→		const context = {
   127→			...entry.context,
   128→			occurrenceCount: entry.count,
   129→			fingerprint,
   130→			firstOccurrence: new Date(entry.firstOccurrence).toISOString(),
   131→		};
   132→
   133→		this.sendToClient({ level: entry.level, err: entry.error, context });
   134→	}
   135→
   136→	private sendToClient({
   137→		level,
   138→		err,
   139→		context,
   140→	}: {
   141→		level: RollbarLevel;
   142→		err: Error | string;
   143→		context: Record<string, unknown>;
   144→	}): void {
   145→		const args:
   146→			| [string, Record<string, unknown>]
   147→			| [string, Error, Record<string, unknown>] =
   148→			typeof err === 'string' ? [err, context] : [err.message, err, context];
   149→
   150→		switch (level) {
   151→			case 'error':
   152→				rollbar.error(...args);
   153→				break;
   154→			case 'warning':
   155→				rollbar.warning(...args);
   156→				break;
   157→			case 'info':
   158→				rollbar.info(...args);
   159→				break;
   160→		}
   161→	}
   162→
   163→	private createFingerprint({
   164→		level,
   165→		err,
   166→	}: {
   167→		level: RollbarLevel;
   168→		err: Error | string;
   169→	}): string {
   170→		const raw = typeof err === 'string' ? err : err.message;
   171→		const message = raw.replace(/\d+(\.\d+)?/g, '*');
   172→		const stackFrames =
   173→			typeof err === 'string' ? '' : (err.stack ?? '').split('\n').slice(1, 4).join('\n');
   174→
   175→		return createHash('sha256')
   176→			.update(`${level}:${message}:${stackFrames}`)
   177→			.digest('hex');
   178→	}
   179→
   180→	private startIntervals(): void {
   181→		this.flushInterval = setInterval(() => {
   182→			this.flush();
   183→		}, FLUSH_INTERVAL_MS);
   184→
   185→		this.flushInterval.unref();
   186→	}
   187→
   188→	private stopIntervals(): void {
   189→		if (this.flushInterval) {
   190→			clearInterval(this.flushInterval);
   191→			this.flushInterval = null;
   192→		}
   193→	}
   194→}
