    37→export function transform(data: Rollbar.Dictionary): void {
    38→	let correlationId;
    39→	try {
    40→		correlationId = correlator.getId();
    41→	} catch {
    42→		correlationId = null;
    43→	}
    44→
    45→	data['custom'] ??= {};
    46→	(data['custom'] as Record<string, unknown>)['correlationId'] = correlationId;
    47→
    48→	const rollbarOptions = requestStore.get({ key: 'rollbar' });
    49→	if (rollbarOptions) {
    50→		mergeFieldsAndData({ data, rollbarOptions });
    51→		const { issueTitle } = rollbarOptions;
    52→		if (issueTitle) {
    53→			overrideIssueTitle({ data, issueTitle });
    54→		}
    55→	}
    56→}
    57→
    58→export function overrideIssueTitle({
    59→	data,
    60→	issueTitle,
    61→}: {
    62→	data: Rollbar.Dictionary;
    63→	issueTitle: string;
    64→}): void {
    65→	if (isDataWithTraceChain({ data })) {
    66→		const dataWithTraceChain = data as dataWithTraceChain;
    67→		const firstException = dataWithTraceChain.body.trace_chain[0];
    68→		if (isObjectWithException({ data: firstException })) {
    69→			const firstExceptionWithMessage = firstException as objectWithException;
    70→			firstExceptionWithMessage.exception.message = issueTitle;
    71→		}
    72→	}
    73→}
    74→
    75→export function mergeFieldsAndData({
    76→	data,
    77→	rollbarOptions,
    78→}: {
    79→	data: Rollbar.Dictionary;
    80→	rollbarOptions: RollbarOptions;
    81→}): void {
    82→	data['custom'] = data['custom'] ?? {};
    83→	const custom = data['custom'] as Record<string, unknown>;
    84→	if (rollbarOptions.fields) {
    85→		Object.assign(custom, rollbarOptions.fields);
    86→	}
    87→
    88→	const fingerprint = rollbarOptions.fingerprintContext
    89→		? { fingerprintContext: rollbarOptions.fingerprintContext }
    90→		: undefined;
    91→	if (rollbarOptions.data || fingerprint) {
    92→		if (!custom['extraArgs'] || typeof custom['extraArgs'] !== 'object') {
    93→			custom['extraArgs'] = {};
    94→		}
    95→		Object.assign(
    96→			custom['extraArgs'] as Record<string, unknown>,
    97→			rollbarOptions.data,
    98→			fingerprint,
    99→		);
   100→	}
   101→}
